use aiken/collection/list
use cardano/assets
use cardano/transaction.{find_input}

pub type PriceDatum = Int

validator price_check {
  spend(_datum, redeemer: OutputReference, _own_ref, self) {
    expect Some(ref_input) = find_input(self.reference_inputs, redeemer)
    expect Some(price_data) = ref_input.output.datum
    expect price: PriceDatum = price_data
    list.any(self.outputs, fn(o) { assets.lovelace_of(o.value) >= price })
  }
}

