use aiken/collection/list
use cardano/assets

validator auth_nft_mint {
  mint(_redeemer, _policy_id, self) {
    list.any(
      self.inputs,
      fn(input) {
        assets.has_nft(
          input.output.value,
          #"cafe0000000000000000000000000000000000000000000000000000",
          "Auth",
        )
      },
    )
  }
}

Scanning `self.inputs` for an NFT in a spend validator is insecure because an attacker can include a different input that holds the NFT, satisfying the check without the script UTxO itself holding the asset. For example:

// INSECURE
list.any(self.inputs, fn(i) { assets.has_nft(i.output.value, policy, name) })

The fix is to resolve the validator's own input using the `own_ref` argument provided by the spend handler:

// SECURE
let own_input = transaction.resolve_input(self.inputs, own_ref)
assets.has_nft(own_input.output.value, policy, name)

This anchors the check to the exact UTxO being spent, not any arbitrary input in the transaction.

